define void @select_2x2_bot(i1 %cond, ptr %lhs, ptr %rhs, ptr %out) !prof !0 {
  %lhsv = load <4 x float>, ptr %lhs, align 16
  %rhsv = load <4 x float>, ptr %rhs, align 16
  %op = select i1 %cond, <4 x float> %lhsv, <4 x float> %rhsv, !prof !1
  call void @llvm.matrix.column.major.store.v4f32.i64(<4 x float> %op, ptr %out, i64 2, i1 false, i32 2, i32 2)
  ret void
}

; Function Attrs: nocallback nofree nosync nounwind willreturn memory(argmem: write)
declare void @llvm.matrix.column.major.store.v4f32.i64(<4 x float>, ptr nocapture writeonly, i64, i1 immarg, i32 immarg, i32 immarg) #0

attributes #0 = { nocallback nofree nosync nounwind willreturn memory(argmem: write) }

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}
